hudson.tasks.BatchFile.command:
@echo off
chcp 65001 >nul
set PYTHONIOENCODING=utf-8
set "BASH=E:\Git\bin\bash.exe"
if not exist "%BASH%" (
  echo ERROR: Git bash not found: %BASH%
  exit /b 1
)
if exist "%JENKINS_HOME%\.apk-site-env" (
  "%BASH%" -lc "set -a; source \"%JENKINS_HOME%/.apk-site-env\"; set +a"
)
if not exist "%JENKINS_HOME%\scripts\commercial_android_pipeline.sh" (
  echo ERROR: missing pipeline script
  exit /b 1
)
"%BASH%" "%JENKINS_HOME%\scripts\commercial_android_pipeline.sh"
exit /b %ERRORLEVEL%
